// Google AdSense 광고 단위
// AdSense 대시보드에서 광고 단위 생성 후 data-ad-slot 값을 교체하세요.
interface Props {
  slot?: string;       // 광고 단위 슬롯 ID (예: "1234567890")
  format?: string;     // auto, horizontal, vertical, rectangle
  layout?: string;     // in-article, in-feed 등
  responsive?: boolean;
}

const {
  slot = '',
  format = 'auto',
  layout,
  responsive = true,
} = Astro.props;
---

{slot && (
  <div class="ad-container">
    <ins class="adsbygoogle"
      style="display:block"
      data-ad-client="ca-pub-3564426383519521"
      data-ad-slot={slot}
      data-ad-format={format}
      {...(layout && { 'data-ad-layout': layout })}
      {...(responsive && { 'data-full-width-responsive': 'true' })}
    ></ins>
    <script>
      (adsbygoogle = window.adsbygoogle || []).push({});
    </script>
  </div>
)}

<style>
  .ad-container {
    margin: 2rem 0;
    min-height: 100px;
    text-align: center;
  }
</style>

