---
// Google AdSense 광고 단위
// AdSense 대시보드에서 광고 단위 생성 후 data-ad-slot 값을 교체하세요.
interface Props {
  slot?: string;       // 광고 단위 슬롯 ID (예: "1234567890")
  format?: string;     // auto, horizontal, vertical, rectangle
  layout?: string;     // in-article, in-feed 등
  responsive?: boolean;
}

const {
  slot = '',
  format = 'auto',
  layout,
  responsive = true,
} = Astro.props;
---

{slot && (
  <div class="ad-container" data-ad-slot={slot} data-ad-format={format} data-ad-layout={layout || ''} data-ad-responsive={responsive ? 'true' : 'false'} style="display:none;">
    <ins class="adsbygoogle"
      style="display:block"
      data-ad-client="ca-pub-3564426383519521"
      data-ad-slot={slot}
      data-ad-format={format}
      {...(layout && { 'data-ad-layout': layout })}
      {...(responsive && { 'data-full-width-responsive': 'true' })}
    ></ins>
  </div>
)}

<script is:inline>
(function() {
  function hasAdConsent() {
    try {
      var consent = JSON.parse(localStorage.getItem('cookie-consent'));
      return consent && consent.ads;
    } catch(e) {
      return false;
    }
  }

  function loadAds() {
    var containers = document.querySelectorAll('.ad-container');
    containers.forEach(function(container) {
      if (container.dataset.adLoaded) return;
      container.style.display = '';
      container.dataset.adLoaded = 'true';
      try {
        (adsbygoogle = window.adsbygoogle || []).push({});
      } catch(e) {}
    });
  }

  if (hasAdConsent()) {
    loadAds();
  }

  window.addEventListener('cookie-consent-updated', function(e) {
    if (e.detail && e.detail.ads) {
      loadAds();
    } else {
      document.querySelectorAll('.ad-container').forEach(function(c) {
        c.style.display = 'none';
      });
    }
  });
})();
</script>

<style>
  .ad-container {
    margin: 2rem 0;
    min-height: 100px;
    text-align: center;
  }
</style>

