        ✉ Email
      </a>
      <a href="/privacy/">Privacy Policy</a>
      <a href="/contact/">Contact</a>
      <button class="footer-cookie-btn" onclick="window.openCookieSettings && window.openCookieSettings()">쿠키 설정</button>
    </div>
    <p class="footer-credit">Built with Astro</p>
  </div>
