<style>
  .site-footer {
    background: var(--surface-bg);
    padding: 40px 20px;
    margin-top: 40px;
    text-align: center;
    color: #8a9a92;
    font-size: 0.85em;
    position: relative;
    border-top: 1px solid var(--surface-border);
  }

  .footer-gradient {
    display: none;
  }

  .footer-inner {
    max-width: 800px;
    margin: 0 auto;
    display: flex;
    justify-content: space-between;
    align-items: center;
  }

  .footer-links {
    display: flex;
    gap: 16px;
  }

  .footer-links a {
    color: #8a9a92;
    text-decoration: none;
    display: flex;
    align-items: center;
    gap: 4px;
  }

  .footer-links a:hover,
  .footer-cookie-btn:hover {
    color: var(--frog-green);
  }

  .footer-cookie-btn {
    background: none;
    border: none;
    color: #8a9a92;
    font: inherit;
    font-size: inherit;
    cursor: pointer;
    padding: 0;
  }

  .footer-credit {
    color: #b0c0b8;
    font-size: 0.85em;
  }

  @media (max-width: 600px) {
    .footer-inner {
      flex-direction: column;
      gap: 8px;
    }
  }
</style>

